import React, { useRef, useState } from 'react';
import { PageContainer } from '@ant-design/pro-layout';
import type { ProColumns, ActionType } from '@ant-design/pro-table';
import ProTable from '@ant-design/pro-table';
import { alarmAudits } from '@/services/api';
import type { API } from '@/services/typings';
import { SaveCsv, csvFormat, getTablePaginationConfig, t } from '../../../global';
import { useIntl } from '@umijs/max';
import { Breadcrumb, Button, Tooltip } from 'antd';

const AuditList: React.FC = () => {
  const actionRef = useRef<ActionType>();
  const [pageParams, setPageParams] = useState<Partial<API.PageParams>>();
  const intl = useIntl();

  const plain = (text: string, defaultMessage = '') => t(`pages.AuditList.AlarmAuditList.${text}`, true, defaultMessage || text, intl) as string;

  const typeEnumMap = (i: number) => {
    switch (i) {
      case 0:
        return plain(
          'IP whiltelist',
          'Access attempt outside the IP whiltelist',
        );
      case 1:
        return plain('ExceedThirtyAccessAttempts',
          'Over 30 consecutive access attempts');
      case 2:
        return plain(
          'MultipleAccessAttemptsWithinOneMinute',
          'Multiple access attempts within one minute',
        );
      case 3:
        return plain(
          'ExceedThirtyLoginAttempts',
          'Over 30 consecutive login attempts',
        );
      case 4:
        return plain(
          'MultipleLoginsAttemptsWithinOneMinute',
          'Multiple login attempts within one minute',
        );
      case 5:
        return plain(
          'MultipleLoginsAttemptsWithinOneHour',
          'Multiple login attempts within one hour',
        );
      case 6:
        return plain(
          'ExceedIPv6PrefixAttempts',
          'Too many consecutive access attempts from a single IPv6 prefix',
        );
      default:
        return i.toString();
    }
  };

  const renderTarget = (record: API.AlarmAuditListItem) => {
    let type = record.typ ?? 0;
    if (type < 3) {
      return record.device ?? '-';
    } else if (type < 6) {
      return record.account ?? '-';
    }
    return '-';
  }

  const renderFrom = (record: API.AlarmAuditListItem) => {
    let type = record.typ ?? 0;
    if (type < 3) {
      let txt = '';
      let local_info = {} as any;
      try {
        local_info = JSON.parse(record.info || '{}');
        if (local_info['id']) txt += local_info['id'];
        if (local_info['name']) {
          if (txt) txt += '-';
          txt += local_info['name'];
        }
        if (local_info['ip']) {
          txt += '@' + local_info['ip'];
        }
      } catch (e) { }
      return txt;
    } else if (type < 6) {
      let txt = '';
      let local_info = {} as any;
      try {
        local_info = JSON.parse(record.info || '{}');
        let device_info = local_info['device_info'] as any;
        if (device_info['os']) txt += device_info['os'];
        if (device_info['type']) {
          if (txt) txt += ' ';
          txt += device_info['type'];
        }
        if (device_info['name']) {
          if (txt) txt += '-';
          txt += device_info['name'];
        }
        if (local_info['ip']) {
          txt += '@' + local_info['ip'];
        }
      } catch (e) { }
      return txt;
    } else {
      return '-';
    }
  }

  const exportCsv = async () => {
    let allItems: API.AlarmAuditListItem[] = [];
    let total = 0;
    const pageSize = 100;
    let current = 0;
    do {
      current++;
      const items = await alarmAudits({ ...pageParams, current: current, pageSize: pageSize });
      if (total == 0 && items.total != null) {
        total = items.total;
      }
      if (items.data != null) {
        allItems = allItems.concat(items.data);
      }
    } while (current < 10 && pageSize * current < total);

    const titles = [
      plain('Type'),
      plain('Login Device / Local Device'),
      plain('Login Account / Remote Device'),
      plain('Event Time'),
    ];
    const rows: string[][] = [];
    allItems.forEach((record) => {
      const row: string[] = [];
      row.push(typeEnumMap(record.typ || 0));
      row.push(renderFrom(record) || '-');
      row.push(renderTarget(record) || '-');
      row.push(csvFormat(new Date((record.created_at || 0) * 1000).toLocaleString()));
      rows.push(row);
    });
    SaveCsv(titles, rows, plain('exportFilename', 'AlarmAudit'));
  };

  const columns: ProColumns<API.AlarmAuditListItem>[] = [
    {
      title: t('Type'),
      dataIndex: 'typ',
      valueType: 'select',
      valueEnum: {
        0: {
          text: typeEnumMap(0),
        },
        1: {
          text: typeEnumMap(1),
        },
        2: {
          text: typeEnumMap(2),
        },
        3: {
          text: typeEnumMap(3),
        },
        4: {
          text: typeEnumMap(4),
        },
      },
      render: (_, record) => typeEnumMap(record.typ || 0),
    },
    {
      title: plain('Login Device / Local Device'),
      search: false,
      hideInSearch: true,
      render: (_, record) => {
        return renderFrom(record);
      },
    },
    {
      title: plain('Login Account / Remote Device'),
      hideInSearch: true,
      render: (_, record) => {
        return renderTarget(record);
      },
    },
    {
      title: plain('Login Account'),
      dataIndex: 'account',
      hideInTable: true,
    },
    {
      title: plain('Device ID'),
      dataIndex: 'device',
      hideInDescriptions: true,
      hideInTable: true,
      tip: plain('Remote Device'),
    },
    {
      title: plain('Device Name'),
      dataIndex: 'report_device_name',
      hideInDescriptions: true,
      hideInTable: true,
      tip: plain('Remote Device'),
    },
    {
      title: plain('Event Time'),
      dataIndex: 'created_at',
      valueType: 'dateTime',
      render: (_, record) => new Date((record.created_at || 0) * 1000).toLocaleString(),
    },
  ];

  return (
    <PageContainer
      breadcrumbRender={() => (
        <Breadcrumb items={[
          { title: t('menu.list.audit-list', true) },
          { title: t('menu.list.audit-list.Alarm', true) },
        ]} />
      )}
    >
      <ProTable<API.AlarmAuditListItem, API.PageParams>
        headerTitle={t('Log List')}
        columnsState={{ persistenceType: 'localStorage', persistenceKey: 'alarmlist_columns_state' }}
        actionRef={actionRef}
        rowKey="guid"
        search={{
          labelWidth: 120,
        }}
        request={alarmAudits}
        columns={columns}
        beforeSearchSubmit={(params) => {
          setPageParams(params);
          return params;
        }}
        toolBarRender={() => [
          <Tooltip title={t('exportCsvTip', true, 'Export up to 1000 records at a time')}>
            <Button type="default" onClick={exportCsv}>
              {t('Export as csv')}
            </Button>
          </Tooltip>,
        ]}
        pagination={getTablePaginationConfig("alarm_audit_list")}
      />
    </PageContainer>
  );
};

export default AuditList;
